// PALCO — Normalizador de entrada UazAPI
// Identico ao Sprint 1: extrai number/text/fromMe do payload UazAPI.

const raw = $input.first().json;
const body = raw.body || raw;

let number =
  body.sender ||
  body.from ||
  body.number ||
  body.phone ||
  (body.message && (body.message.sender || body.message.from || body.message.chatid)) ||
  (body.data && (body.data.sender || body.data.from || body.data.chatid)) ||
  '';

if (typeof number === 'string') {
  number = number.replace(/@.+$/, '').replace(/\D/g, '');
}

const text =
  body.text ||
  body.message_text ||
  body.content ||
  (body.message && (body.message.text || body.message.body || body.message.content)) ||
  (body.data && (body.data.text || body.data.body || body.data.message)) ||
  (body.messages && body.messages[0] && (body.messages[0].message || body.messages[0].text)) ||
  '';

const fromMe =
  body.fromMe === true ||
  body.from_me === true ||
  (body.message && body.message.fromMe === true) ||
  (body.data && body.data.fromMe === true) ||
  false;

const messageType =
  body.messageType ||
  body.type ||
  (body.message && body.message.type) ||
  (body.data && body.data.type) ||
  'text';

const isText = typeof text === 'string' && text.trim().length > 0;
const shouldProcess = isText && !fromMe && !!number;

return [{
  json: {
    number,
    text: (text || '').toString().trim(),
    fromMe,
    messageType,
    shouldProcess,
    receivedAt: new Date().toISOString(),
    rawKeys: Object.keys(body)
  }
}];

// PALCO — Router de estado e montador de prompt.
// Decide a rota (onboarding P1/P2/P3/confirma, sessao_semanal) e:
//   1. Aplica a resposta do usuario a ficha (se aplicavel)
//   2. Monta o system prompt dinamico para o Claude
//   3. Prepara o objeto que sera upserted no Supabase
//
// KISS: estado do onboarding e contado via campos da ficha (sem campo extra).
//   - sem row            -> primeiro contato -> apresentacao + P1
//   - tem row, pergunta_atual = 'P1' -> esta mensagem e resposta de P1 -> salva ativo_principal, faz P2
//   - pergunta_atual = 'P2' -> salva publico, faz P3
//   - pergunta_atual = 'P3' -> salva emocao_alvo, confirma onboarding, abre sessao semanal
//   - status_onboarding = 'concluido' -> sessao semanal (usa ficha como contexto)

const norm = $('Normalizar Mensagem').item.json;
const userMessage = norm.text;
const numero = norm.number;

const lookupResp = $input.first().json;
// Supabase REST sempre retorna array (possivelmente vazio). Se vier error shape, tratar.
let usuario = null;
if (Array.isArray(lookupResp) && lookupResp.length > 0) {
  usuario = lookupResp[0];
} else if (Array.isArray(lookupResp) && lookupResp.length === 0) {
  usuario = null;
} else if (lookupResp && lookupResp.error) {
  // erro de Supabase — logamos mas seguimos como se fosse primeiro contato, para nao travar o usuario.
  // o save na frente tambem pode falhar, mas o musico pelo menos recebe resposta.
  usuario = null;
}

// --- Decidir rota ---
let route;           // 'ONBOARDING_INICIO' | 'ONBOARDING_P1_RESP' | 'ONBOARDING_P2_RESP' | 'ONBOARDING_P3_RESP' | 'SESSAO_SEMANAL'
let fichaAtual  = (usuario && usuario.ficha)        || {};
let sessao      = (usuario && usuario.sessao_atual) || { ativa: false };
let calibracao  = (usuario && usuario.calibracao)   || { semanas: [], ajustes_tom: [] };
let statusOnb   = (usuario && usuario.status_onboarding) || 'em_andamento';
let perguntaAtual = (usuario && usuario.pergunta_atual)  || null;

if (!usuario) {
  route = 'ONBOARDING_INICIO';
  perguntaAtual = 'P1';
} else if (statusOnb === 'em_andamento' && perguntaAtual === 'P1') {
  route = 'ONBOARDING_P1_RESP';
  fichaAtual = Object.assign({}, fichaAtual, { ativo_principal: userMessage });
  perguntaAtual = 'P2';
} else if (statusOnb === 'em_andamento' && perguntaAtual === 'P2') {
  route = 'ONBOARDING_P2_RESP';
  fichaAtual = Object.assign({}, fichaAtual, { publico: userMessage });
  perguntaAtual = 'P3';
} else if (statusOnb === 'em_andamento' && perguntaAtual === 'P3') {
  route = 'ONBOARDING_P3_RESP';
  fichaAtual = Object.assign({}, fichaAtual, { emocao_alvo: userMessage });
  perguntaAtual = null;
  statusOnb = 'concluido';
} else if (statusOnb === 'concluido') {
  route = 'SESSAO_SEMANAL';
} else {
  // fallback defensivo: status estranho, reinicia onboarding mas mantem ficha antiga
  route = 'ONBOARDING_INICIO';
  perguntaAtual = 'P1';
  statusOnb = 'em_andamento';
}

// --- Vocabulario e tom (compartilhado entre rotas) ---
const tomPalco = [
  'Voce e o PALCO — assistente de conteudo para Instagram de musicos profissionais.',
  'Voce nao e uma IA generica de marketing. Voce e uma extensao da voz do musico no digital.',
  '',
  'TOM: direto, sem bajulacao. Trata o musico como profissional que ja construiu algo real.',
  'Faz distincoes precisas. Perguntas especificas, nunca genericas. Corta o que e vago.',
  '',
  'VOCABULARIO PROIBIDO: engajamento, alcance, audiencia, conteudo de valor, agregar valor, posicionamento, branding, storytelling, jornada, persona, nicho estrategico, autoridade digital.',
  'Use em vez: pessoas que te seguem, quem vai ver, o que voce posta, o que voce faz, como voce trabalha, quem te contrata, quem aprende com voce.'
].join('\n');

// --- Monta system prompt conforme a rota ---
let systemPrompt;

if (route === 'ONBOARDING_INICIO') {
  systemPrompt = tomPalco + '\n\n' + [
    'CONTEXTO: este musico esta te contatando pela PRIMEIRA VEZ. Nenhuma ficha salva ainda.',
    '',
    'ACAO UNICA NESTA RESPOSTA:',
    '1. Apresente-se em UMA frase curta.',
    '2. Diga que fara 3 perguntas de identidade, uma por vez.',
    '3. Faca APENAS a PERGUNTA 1, exatamente esta:',
    '   "Qual e o seu ativo mais forte — aquilo pelo qual as pessoas te buscam especificamente, nao qualquer musico com o mesmo perfil?"',
    '',
    'NAO faca P2 nem P3 nesta mensagem. Aguarde a resposta.',
    'Nao gere conteudo de Instagram agora — onboarding primeiro.'
  ].join('\n');
} else if (route === 'ONBOARDING_P1_RESP') {
  systemPrompt = tomPalco + '\n\n' + [
    'CONTEXTO: o musico acabou de responder a PERGUNTA 1 (ativo principal).',
    'Resposta dele: "' + userMessage + '"',
    '',
    'ACAO UNICA:',
    '1. Reconheca a resposta em UMA frase curta (sem bajulacao, sem repetir a resposta inteira).',
    '2. Faca APENAS a PERGUNTA 2, exatamente esta:',
    '   "Quem e a pessoa que mais se beneficia do que voce faz? Descreve ela em uma frase."',
    '',
    'NAO faca P3 ainda. Aguarde a resposta.'
  ].join('\n');
} else if (route === 'ONBOARDING_P2_RESP') {
  systemPrompt = tomPalco + '\n\n' + [
    'CONTEXTO: o musico acabou de responder a PERGUNTA 2 (publico).',
    'Ficha parcial salva:',
    '  ativo_principal: ' + (fichaAtual.ativo_principal || '(nao preenchido)'),
    '  publico:         ' + (fichaAtual.publico || userMessage),
    '',
    'ACAO UNICA:',
    '1. Reconheca a resposta em UMA frase curta.',
    '2. Faca APENAS a PERGUNTA 3, exatamente esta:',
    '   "O que voce quer que alguem sinta quando termina de ver um post seu?"',
    '',
    'Aguarde a resposta antes de gerar qualquer conteudo.'
  ].join('\n');
} else if (route === 'ONBOARDING_P3_RESP') {
  systemPrompt = tomPalco + '\n\n' + [
    'CONTEXTO: onboarding concluido. O musico acabou de responder a PERGUNTA 3 (emocao alvo).',
    '',
    'DNA SALVO:',
    '  ativo_principal: ' + (fichaAtual.ativo_principal || '(vazio)'),
    '  publico:         ' + (fichaAtual.publico || '(vazio)'),
    '  emocao_alvo:     ' + (fichaAtual.emocao_alvo || userMessage),
    '',
    'ACAO UNICA:',
    '1. Confirme em UMA frase que o DNA foi salvo: "Entendido. Isso e o seu DNA aqui dentro. Toda semana o conteudo vai partir daqui."',
    '2. Abra a primeira sessao semanal perguntando: "O que aconteceu essa semana que vale ser contado — um show, uma aula, uma gravacao, um momento, uma percepcao?"',
    '',
    'Nao gere o pacote semanal ainda — espere o musico responder o que aconteceu.'
  ].join('\n');
} else if (route === 'SESSAO_SEMANAL') {
  const calibText = (calibracao && calibracao.semanas && calibracao.semanas.length > 0)
    ? JSON.stringify(calibracao.semanas.slice(-3))
    : '(sem calibracao ainda — primeira sessao apos onboarding)';
  systemPrompt = tomPalco + '\n\n' + [
    'CONTEXTO: onboarding concluido. Este musico ja tem DNA salvo.',
    '',
    'DNA DO MUSICO:',
    '  ativo_principal: ' + (fichaAtual.ativo_principal || '(vazio)'),
    '  publico:         ' + (fichaAtual.publico || '(vazio)'),
    '  emocao_alvo:     ' + (fichaAtual.emocao_alvo || '(vazio)'),
    '',
    'CALIBRACAO (ultimas 3 semanas): ' + calibText,
    '',
    'FLUXO DA SESSAO SEMANAL:',
    '- Se a mensagem do musico e vaga (ex: "oi", "bom dia") -> pergunte: "O que aconteceu essa semana que vale ser contado — um show, uma aula, uma gravacao, um momento, uma percepcao?"',
    '- Se a mensagem ja tem um fato concreto da semana -> cruze com o DNA e gere o PACOTE SEMANAL no formato fixo:',
    '',
    '   FEED (caption 3-5 paragrafos)',
    '   REELS (caption 2-3 linhas)',
    '   STORIES (3 frames: provocacao / fato / CTA)',
    '   GANCHO DA SEMANA (max 12 palavras)',
    '   CTA (acao especifica, nao "curte e compartilha")',
    '',
    '- Apos o pacote, pergunte: "Alguma peca que nao soa como voce? Ajusto antes de voce postar."',
    '',
    'REGRAS: nunca invente fatos; se o input for vago, peca especificidade; voz soa como o musico, nao como IA de marketing.'
  ].join('\n');
} else {
  systemPrompt = tomPalco + '\n\nResponda de forma curta pedindo para o musico repetir a mensagem.';
}

// --- Objeto que sera salvo no Supabase (upsert) ---
// Para ONBOARDING_INICIO: cria a row com pergunta_atual=P1 e ficha vazia.
// Para ONBOARDING_P*_RESP: atualiza ficha + pergunta_atual.
// Para SESSAO_SEMANAL: so atualiza atualizado_em (trigger cuida), sem mudar ficha/status.
//   -> saveNeeded=false evita roundtrip desnecessario.
let saveNeeded = true;
let saveBody;

if (route === 'SESSAO_SEMANAL') {
  // KISS Sprint 2: nao persistimos evento_semana/pacote_gerado ainda — isso e Sprint 3.
  // O trigger atualizado_em dispara em qualquer UPDATE, mas evitamos writes desnecessarios.
  saveNeeded = false;
  saveBody = null;
} else {
  saveBody = {
    numero_whatsapp:   numero,
    status_onboarding: statusOnb,
    pergunta_atual:    perguntaAtual,
    ficha:             fichaAtual
  };
}

return [{
  json: {
    route,
    numero,
    userMessage,
    systemPrompt,
    saveNeeded,
    saveBody,
    debug: {
      statusOnb,
      perguntaAtual,
      fichaKeys: Object.keys(fichaAtual),
      existiaRow: !!usuario
    }
  }
}];

// Extrai texto da resposta da API Anthropic.
// Tratar erro da API sem quebrar o workflow (responder algo ao musico).

const r = $input.first().json;
const router = $('Router & Estado').item.json;

let reply = '';
let ok = false;

if (r && Array.isArray(r.content) && r.content.length > 0) {
  const textBlock = r.content.find(b => b && b.type === 'text');
  if (textBlock && textBlock.text) {
    reply = textBlock.text;
    ok = true;
  }
}

if (!ok) {
  const errMsg = (r && r.error && (r.error.message || r.error.type)) || 'erro desconhecido';
  reply = 'PALCO esta temporariamente fora do ar (modo teste). Codigo: ' + errMsg + '. Tenta de novo em 1 minuto — se persistir, avisa o Edilson.';
}

return [{
  json: {
    number:       router.numero,
    reply,
    ok,
    route:        router.route,
    saveNeeded:   router.saveNeeded,
    saveBody:     router.saveBody,
    rawAnthropicKeys: r ? Object.keys(r) : [],
    usage:        (r && r.usage) || null,
    debug:        router.debug
  }
}];
